type RecursivePartial<T> = NonNullable<T> extends object
    ? {
          [P in keyof T]?: NonNullable<T[P]> extends (infer U)[]
              ? RecursivePartial<U>[]
              : NonNullable<T[P]> extends object
              ? RecursivePartial<T[P]>
              : T[P];
      }
    : T;

export const addSearchParams = (
    path: string,
    fieldsValue: RecursivePartial<any>,
    resetFields = true
) => {
    const table_search_params = JSON.stringify({ ...fieldsValue, resetFields });
    const url = new URL(window.location.origin + path);
    // 添加表格searchParams总长度不能超过1000字符，否则失效
    if (table_search_params.length > 1000) {
        console.error('table searchParams too long,character length cannot exceed 1000 !');
        return url.pathname;
    } else {
        url.searchParams.set('table_search_params', table_search_params);
        return url.pathname + url.search;
    }
};
